        --[[ AAAAAAAAAAAAAAAÇAI COM LEITE NINHO NHANANINANINAMNAM ]]
        loadstring((function()
            local data = ""
            
            local function b64(s)
                local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
                local t={}
                s=s:gsub('[^'..b..'=]','')
                for i=1,#s,4 do
                    local a=b:find(s:sub(i,i))-1
                    local c=b:find(s:sub(i+1,i+1))-1
                    local d=b:find(s:sub(i+2,i+2))-1
                    local e=b:find(s:sub(i+3,i+3))-1
                    if a and c and d and e then
                        table.insert(t, string.char((a<<2)|(c>>4)))
                        if s:sub(i+2,i+2)~='=' then
                            table.insert(t, string.char(((c&15)<<4)|(d>>2)))
                        end
                        if s:sub(i+3,i+3)~='=' then
                            table.insert(t, string.char(((d&3)<<6)|e))
                        end
                    end
                end
                return table.concat(t)
            end
            
            local function xor_decrypt(s)
                local keys = {17,62,244,161,108,177,173,132,15,142}
                local r = ""
                for i=1,#s do
                    r = r .. string.char(string.byte(s,i) ~ keys[(i-1)%#keys+1])
                end
                return r
            end
            
            local function unshuffle(s)
                local parts = {}
                for i=1,#s,3 do
                    parts[#parts+1] = s:sub(i,i+2)
                end
                local order = {}
                for i=1,#parts do order[i] = i end
                for i=#parts,2,-1 do
                    local j = math.random(i)
                    order[i], order[j] = order[j], order[i]
                end
                local r = {}
                for i=1,#order do
                    r[i] = parts[order[i]]
                end
                return table.concat(r)
            end
            
            -- Decodifica camada por camada (SEM zlib)
            local l1 = b64(data)
            local l2 = xor_decrypt(l1)
            local l3 = unshuffle(l2)
            local l4 = b64(l3)
            
            return l4
        end)())()
        
